mapper.select:
SELECT SCTM.BUYER_CD ,SCTM.APP_DOC_NUM ,SCTM.APP_DOC_CNT ,SCTM.SUBJECT ,SCTM.SIGN_STATUS ,(CASE WHEN SCTP.SIGN_REQ_TYPE = 'CC' THEN '참조' ELSE SCTP.SIGN_STATUS END) AS PER_SIGN_STATUS ,SCTM.IMPORTANCE_STATUS ,SCTM.DOC_TYPE ,((SELECT MAX(SIGN_DATE) FROM STOCSCTP WHERE GATE_CD = SCTM.GATE_CD AND BUYER_CD = SCTM.BUYER_CD AND APP_DOC_NUM = SCTM.APP_DOC_NUM AND APP_DOC_CNT = SCTM.APP_DOC_CNT AND DEL_FLAG = '0' AND (SIGN_STATUS = 'E' OR SIGN_STATUS = 'R')), 'yyyy-mm-dd hh24:mi') AS SIGN_DATE ,(SCTM.REG_DATE, 'yyyy-mm-dd hh24:mi') AS RFA_DATE_TIME ,SCTM.REG_USER_ID AS REG_USER_ID ,getUserName(SCTM.GATE_CD, SCTM.REG_USER_ID , #{ses.langCd}) AS REG_USER_NM ,'' as DOC_CONTENTS ,SCTP.SIGN_PATH_SQ ,SCTM.ATT_FILE_NUM ,SCTM.GATE_CD ,SCTM.NEXT_SIGN_USER_ID ,(CASE WHEN SCTM.SIGN_STATUS = 'P' THEN CUR.USER_NM ELSE '-' END) AS NEXT_SIGN_USER_NM ,SCTP.SIGN_REQ_TYPE ,SCTP.DOC_SQ ,SCTP.SIGN_USER_ID ,(GETDEPTNAME(SCTM.GATE_CD, SCTM.BUYER_CD, SCTM.DEPT_CD, #{ses.langCd}), GETDEPTNAME(RCUR.GATE_CD, RCUR.COMPANY_CD, RCUR.DEPT_CD, #{ses.langCd})) AS REG_DEPT_NM ,SCTM.APP_AMT
,(CASE WHEN SCTP.SIGN_REQ_TYPE IN ('E', 'ES', 'EP', 'A') THEN SCTP.SIGN_PATH_SQ '/' (SELECT COUNT(*) FROM STOCSCTP SCTP WHERE SCTP.GATE_CD = SCTM.GATE_CD AND SCTP.BUYER_CD = SCTM.BUYER_CD AND SCTP.APP_DOC_NUM = SCTM.APP_DOC_NUM AND SCTP.APP_DOC_CNT = SCTM.APP_DOC_CNT AND SCTP.SIGN_REQ_TYPE IN ('E', 'ES', 'EP', 'A') AND SCTP.DEL_FLAG = '0') ELSE (SELECT TO_CHAR(COUNT(*)) FROM STOCSCTP SCTP WHERE SCTP.GATE_CD = SCTM.GATE_CD AND SCTP.BUYER_CD = SCTM.BUYER_CD AND SCTP.APP_DOC_NUM = SCTM.APP_DOC_NUM AND SCTP.APP_DOC_CNT = SCTM.APP_DOC_CNT AND SCTP.SIGN_REQ_TYPE IN ('E', 'ES', 'EP', 'A') AND SCTP.DEL_FLAG = '0') END) AS VIEW_CNT
,(SELECT CONVERT(varchar(10), CONVERT(INT, (MAX(SIGN_PATH_SQ), 0))) FROM STOCSCTP SCTP WHERE SCTP.GATE_CD = SCTM.GATE_CD AND SCTP.BUYER_CD = SCTM.BUYER_CD AND SCTP.APP_DOC_NUM = SCTM.APP_DOC_NUM AND SCTP.APP_DOC_CNT = SCTM.APP_DOC_CNT AND SCTP.DEL_FLAG = '0' AND SCTP.SIGN_STATUS IN ('E', 'R')) '/' (SELECT CONVERT(varchar(10), CONVERT(INT, COUNT(*))) FROM STOCSCTP SCTP WHERE SCTP.GATE_CD = SCTM.GATE_CD AND SCTP.BUYER_CD = SCTM.BUYER_CD AND SCTP.APP_DOC_NUM = SCTM.APP_DOC_NUM AND SCTP.APP_DOC_CNT = SCTM.APP_DOC_CNT AND SCTP.DEL_FLAG = '0' AND SCTP.SIGN_REQ_TYPE = 'E') AS VIEW_CNT
FROM STOCSCTM SCTM INNER JOIN STOCSCTP SCTP ON (SCTM.GATE_CD = SCTP.GATE_CD AND SCTM.BUYER_CD = SCTP.BUYER_CD AND SCTM.APP_DOC_NUM = SCTP.APP_DOC_NUM AND SCTM.APP_DOC_CNT = SCTP.APP_DOC_CNT) LEFT OUTER JOIN STOCCVUR CUR ON (SCTM.GATE_CD = CUR.GATE_CD AND SCTM.NEXT_SIGN_USER_ID = CUR.USER_ID) LEFT OUTER JOIN STOCCVUR RCUR ON (SCTM.GATE_CD = RCUR.GATE_CD AND SCTM.REG_USER_ID = RCUR.USER_ID) WHERE SCTM.GATE_CD = #{ses.gateCd} AND SCTP.SIGN_USER_ID = #{ses.userId} AND SCTM.DEL_FLAG = '0' AND SCTP.DEL_FLAG = '0'
AND ((SCTP.SIGN_STATUS IN ('E','R') AND SCTP.SIGN_REQ_TYPE IN ('E', 'ES', 'EP')) OR (SCTM.SIGN_STATUS IN ('E', 'ES', 'EP') AND SCTP.SIGN_REQ_TYPE = 'CC')) AND SCTM.SIGN_STATUS IN ('P','E','R') AND SCTP.SIGN_USER_ID = #{ses.userId}
AND SCTP.SIGN_STATUS = 'P' AND SCTM.SIGN_STATUS = 'P' AND SCTM.NEXT_SIGN_USER_ID = #{ses.userId}
AND SCTM.REG_DATE >= (#{RFA_FROM_DATE}) AND SCTM.REG_DATE <= (#{RFA_TO_DATE})
AND SCTM.SIGN_STATUS = #{SIGN_STATUS}
AND SCTM.DOC_TYPE = #{DOCUMENT_TYPE}
AND UPPER(SCTM.REG_USER_ID) LIKE '%' UPPER(#{USER_ID}) '%'
AND UPPER(getUserName(SCTM.GATE_CD, SCTM.REG_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{USER_NM}) '%'
AND UPPER(REPLACE(SCTM.SUBJECT, ' ', '')) LIKE '%' UPPER(REPLACE(#{DOCUMENT_NM}, ' ', '')) '%'
ORDER BY SCTM.REG_DATE DESC

SELECT DISTINCT SIGN_STATUS AS MY_SIGN_STATUS
  FROM STOCSCTP
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND APP_DOC_NUM = #{APP_DOC_NUM}
   AND APP_DOC_CNT = #{APP_DOC_CNT}
   AND SIGN_USER_ID = #{ses.userId}
   AND DEL_FLAG = '0'

		SELECT
            (CASE WHEN SIGN_DATE IS NULL THEN 'Y' ELSE 'N' END) AS UPDATE_FLAG
          FROM STOCSCTP
         WHERE GATE_CD = #{ses.gateCd}
           AND BUYER_CD = #{BUYER_CD}
           AND APP_DOC_NUM = #{APP_DOC_NUM}
           AND APP_DOC_CNT = #{APP_DOC_CNT}
           AND SIGN_REQ_TYPE = 'CC'
           AND SIGN_USER_ID = #{ses.userId}

