   AND APP_DOC_NUM = #{APP_DOC_NUM}
   AND APP_DOC_CNT = #{APP_DOC_CNT}
   AND SIGN_REQ_TYPE = 'CC'
   AND SIGN_USER_ID = #{ses.userId}

