SELECT A.* FROM ( SELECT GETCOMCODE(HD.GATE_CD, 'M070', 'BID', 0, #{ses.langCd}) AS TYPE , 'BID' AS RFX_TYPE , HD.BUYER_CD ,getBuyerNames(HD.GATE_CD, HD.BUYER_CD, 'BID', HD.BID_NUM, HD.BID_CNT, null, #{ses.langCd}) AS BUYER_NM , HD.ANN_NO , HD.ANN_ITEM , HD.ANN_DATE , HD.CONT_TYPE1 ,GETCOMCODE(HD.GATE_CD, 'M301', HD.CONT_TYPE1, 0, #{ses.langCd}) AS CONT_TYPE1_LOC , HD.CONT_TYPE2 ,GETCOMCODE(HD.GATE_CD, 'M302', HD.CONT_TYPE2, 0, #{ses.langCd}) AS CONT_TYPE2_LOC , HD.CONT_TYPE3 ,GETCOMCODE(HD.GATE_CD, 'M303', HD.CONT_TYPE3, 0, #{ses.langCd}) AS CONT_TYPE3_LOC , SUBSTR(HD.APP_BEGIN_DATE, 1, 4) '-' SUBSTR(HD.APP_BEGIN_DATE, 5, 2) '-' SUBSTR(HD.APP_BEGIN_DATE, 7, 2) ' ' SUBSTR(HD.APP_BEGIN_TIME, 1, 2) ':' SUBSTR(HD.APP_BEGIN_TIME, 3, 2) AS APP_BEGIN_DATETIME , SUBSTR(HD.APP_END_DATE, 1, 4) '-' SUBSTR(HD.APP_END_DATE, 5, 2) '-' SUBSTR(HD.APP_END_DATE, 7, 2) ' ' SUBSTR(HD.APP_END_TIME, 1, 2) ':' SUBSTR(HD.APP_END_TIME, 3, 2) AS APP_END_DATETIME ,(CASE WHEN ES.ESTM_CONFIRM_DATE IS NULL THEN '0' ELSE '1' END) AS BID_STATUS , HD.BID_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd}) AS BID_USER_NM , HD.ESTM_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.ESTM_USER_ID, #{ses.langCd}) AS ESTM_USER_NM , HD.BID_NUM , HD.BID_CNT ,(ES.SIGN_STATUS,'') AS SIGN_STATUS ,(HD.ESTM_TYPE,'ES') AS ESTM_TYPE ,(CASE WHEN ES.ESTM_CONFIRM_DATE IS NULL THEN '0' ELSE '1' END) AS BID_STATUS_LOC , HD.BID_STATUS AS BID_STATUS2 , ES.APP_DOC_CNT AS APP_DOC_CNT , ES.APP_DOC_NUM AS APP_DOC_NUM FROM STOCBDHD HD LEFT OUTER JOIN STOCBDES ES ON (HD.GATE_CD = ES.GATE_CD AND HD.BUYER_CD = ES.BUYER_CD AND HD.BID_NUM = ES.BID_NUM AND HD.BID_CNT = ES.BID_CNT AND ES.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{ses.companyCd} AND HD.SIGN_STATUS = 'E' AND HD.BID_STATUS not in ('9999', '2303') AND HD.DEL_FLAG = '0' AND (HD.ESTM_TYPE,'ES') != 'ES' -- 예가 생략 아니것
AND EXISTS ( SELECT '1' FROM STOCBDDT WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND BID_NUM = HD.BID_NUM AND BID_CNT = HD.BID_CNT AND PR_BUYER_CD = #{BUYER_CD} AND DEL_FLAG = '0' )
AND EXISTS ( SELECT '1' FROM STOCBDDT WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND BID_NUM = HD.BID_NUM AND BID_CNT = HD.BID_CNT AND UPPER(getCustName(GATE_CD, PR_BUYER_CD)) LIKE '%' UPPER(#{BUYER_NM}) '%' AND DEL_FLAG = '0' )
UNION ALL
SELECT GETCOMCODE(HD.GATE_CD, 'M070', HD.RFX_TYPE, 0, #{ses.langCd}) AS TYPE , HD.RFX_TYPE , HD.BUYER_CD ,getBuyerNames(HD.GATE_CD, HD.BUYER_CD, 'RFX', HD.RFX_NUM, HD.RFX_CNT, null, #{ses.langCd}) AS BUYER_NM , HD.RFX_NUM AS ANN_NO , HD.RFX_SUBJECT AS ANN_ITEM , (HD.SIGN_DATE,'YYYYMMDD') AS ANN_DATE , HD.VENDOR_OPEN_TYPE AS CONT_TYPE1 ,GETCOMCODE(HD.GATE_CD, 'M301', HD.VENDOR_OPEN_TYPE, 0, #{ses.langCd}) AS CONT_TYPE1_LOC , 'LP' AS CONT_TYPE2 ,(CASE WHEN HD.RFX_TYPE = 'RPC' or HD.RFX_TYPE = 'RCA' or HD.RFX_TYPE = 'RFQ' or HD.RFX_TYPE = 'RYQ' THEN NULL ELSE GETCOMCODE(HD.GATE_CD, 'M301', 'LP', 0, #{ses.langCd}) END) AS CONT_TYPE2_LOC , HD.AMT_TYPE AS CONT_TYPE3 ,GETCOMCODE(HD.GATE_CD, 'M303', HD.AMT_TYPE, 0, #{ses.langCd}) AS CONT_TYPE3_LOC , (RFX_START_DATE, 'YYYY-MM-DD HH24:MI') AS APP_BEGIN_DATETIME , (RFX_END_DATE, 'YYYY-MM-DD HH24:MI') AS APP_END_DATETIME ,(CASE WHEN ES.ESTM_CONFIRM_DATE IS NULL THEN '0' ELSE '1' END) AS BID_STATUS , HD.CTRL_USER_ID AS BID_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.CTRL_USER_ID, #{ses.langCd}) AS BID_USER_NM , HD.ESTM_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.ESTM_USER_ID, #{ses.langCd}) AS ESTM_USER_NM , HD.RFX_NUM AS BID_NUM , HD.RFX_CNT AS BID_CNT ,(ES.SIGN_STATUS,'') AS SIGN_STATUS ,(CASE WHEN (HD.EST_PRICE_TYPE,'0') = '1' THEN 'SE' ELSE 'SE' END) AS ESTM_TYPE ,(CASE WHEN ES.ESTM_CONFIRM_DATE IS NULL THEN '0' ELSE '1' END) AS BID_STATUS_LOC , HD.PROGRESS_CD AS BID_STATUS2 , ES.APP_DOC_CNT AS APP_DOC_CNT , ES.APP_DOC_NUM AS APP_DOC_NUM FROM STOCRQHD HD LEFT OUTER JOIN STOCBDES ES ON (HD.GATE_CD = ES.GATE_CD AND HD.BUYER_CD = ES.BUYER_CD AND HD.RFX_NUM = ES.BID_NUM AND HD.RFX_CNT = ES.BID_CNT AND ES.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{ses.companyCd} AND HD.RFX_CNT = '1' AND HD.SIGN_STATUS = 'E' AND HD.DEL_FLAG = '0' AND (HD.EST_PRICE_TYPE,'0') != '0' -- 예가 생략 아니것
AND EXISTS ( SELECT '1' FROM STOCRQDT WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND RFX_NUM = HD.RFX_NUM AND RFX_CNT = HD.RFX_CNT AND PR_BUYER_CD = #{BUYER_CD} AND DEL_FLAG = '0' )
AND EXISTS (SELECT '1' FROM STOCRQDT WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND RFX_NUM = HD.RFX_NUM AND RFX_CNT = HD.RFX_CNT AND UPPER(getCustName(GATE_CD, PR_BUYER_CD)) LIKE '%' UPPER(#{BUYER_NM}) '%' AND DEL_FLAG = '0' )
) A WHERE 1 = 1
AND A.BID_STATUS = #{BID_STATUS}
AND A.APP_DOC_CNT = #{APP_DOC_CNT}
AND A.APP_DOC_NUM = #{APP_DOC_NUM}

SELECT SCTM.BUYER_CD ,SCTM.APP_DOC_NUM ,SCTM.APP_DOC_CNT ,SCTM.SUBJECT ,SCTM.SIGN_STATUS ,(CASE WHEN SCTP.SIGN_REQ_TYPE = 'CC' THEN '참조' ELSE SCTP.SIGN_STATUS END) AS PER_SIGN_STATUS ,SCTM.IMPORTANCE_STATUS ,SCTM.DOC_TYPE ,((SELECT MAX(SIGN_DATE) FROM STOCSCTP WHERE GATE_CD = SCTM.GATE_CD AND BUYER_CD = SCTM.BUYER_CD AND APP_DOC_NUM = SCTM.APP_DOC_NUM AND APP_DOC_CNT = SCTM.APP_DOC_CNT AND DEL_FLAG = '0' AND (SIGN_STATUS = 'E' OR SIGN_STATUS = 'R')), 'yyyy-mm-dd hh24:mi') AS SIGN_DATE ,(SCTM.REG_DATE, 'yyyy-mm-dd hh24:mi') AS RFA_DATE_TIME ,SCTM.REG_USER_ID AS REG_USER_ID ,getUserName(SCTM.GATE_CD, SCTM.REG_USER_ID , #{ses.langCd}) AS REG_USER_NM ,'' as DOC_CONTENTS ,SCTP.SIGN_PATH_SQ ,SCTM.ATT_FILE_NUM, getFileCount(SCTM.GATE_CD, SCTM.ATT_FILE_NUM) AS ATT_FILE_CNT ,SCTM.NEXT_SIGN_USER_ID ,(CASE WHEN SCTM.SIGN_STATUS = 'P' THEN CUR.USER_NM ELSE '-' END) AS NEXT_SIGN_USER_NM ,SCTP.SIGN_REQ_TYPE ,SCTP.DOC_SQ ,SCTP.SIGN_USER_ID ,(GETDEPTNAME(SCTM.GATE_CD, SCTM.BUYER_CD, SCTM.DEPT_CD, #{ses.langCd}), GETDEPTNAME(RCUR.GATE_CD, RCUR.COMPANY_CD, RCUR.DEPT_CD, #{ses.langCd})) AS REG_DEPT_NM ,SCTM.APP_AMT
,(CASE WHEN SCTP.SIGN_REQ_TYPE IN ('E', 'ES', 'EP') THEN SCTP.SIGN_PATH_SQ '/' (SELECT COUNT(*) FROM STOCSCTP SCTP WHERE SCTP.GATE_CD = SCTM.GATE_CD AND SCTP.BUYER_CD = SCTM.BUYER_CD AND SCTP.APP_DOC_NUM = SCTM.APP_DOC_NUM AND SCTP.APP_DOC_CNT = SCTM.APP_DOC_CNT AND SCTP.SIGN_REQ_TYPE IN ('E', 'ES', 'EP') AND SCTP.DEL_FLAG = '0') ELSE (SELECT TO_CHAR(COUNT(*)) FROM STOCSCTP SCTP WHERE SCTP.GATE_CD = SCTM.GATE_CD AND SCTP.BUYER_CD = SCTM.BUYER_CD AND SCTP.APP_DOC_NUM = SCTM.APP_DOC_NUM AND SCTP.APP_DOC_CNT = SCTM.APP_DOC_CNT AND SCTP.SIGN_REQ_TYPE IN ('E', 'ES', 'EP') AND SCTP.DEL_FLAG = '0') END) AS VIEW_CNT
,(SELECT CONVERT(varchar(10), CONVERT(INT, (MAX(SIGN_PATH_SQ), 0))) FROM STOCSCTP SCTP WHERE SCTP.GATE_CD = SCTM.GATE_CD AND SCTP.BUYER_CD = SCTM.BUYER_CD AND SCTP.APP_DOC_NUM = SCTM.APP_DOC_NUM AND SCTP.APP_DOC_CNT = SCTM.APP_DOC_CNT AND SCTP.DEL_FLAG = '0' AND SCTP.SIGN_STATUS IN ('E', 'R')) '/' (SELECT CONVERT(varchar(10), CONVERT(INT, COUNT(*))) FROM STOCSCTP SCTP WHERE SCTP.GATE_CD = SCTM.GATE_CD AND SCTP.BUYER_CD = SCTM.BUYER_CD AND SCTP.APP_DOC_NUM = SCTM.APP_DOC_NUM AND SCTP.APP_DOC_CNT = SCTM.APP_DOC_CNT AND SCTP.DEL_FLAG = '0' AND SCTP.SIGN_REQ_TYPE = 'E') AS VIEW_CNT
FROM STOCSCTM SCTM INNER JOIN STOCSCTP SCTP ON (SCTM.GATE_CD = SCTP.GATE_CD AND SCTM.BUYER_CD = SCTP.BUYER_CD AND SCTM.APP_DOC_NUM = SCTP.APP_DOC_NUM AND SCTM.APP_DOC_CNT = SCTP.APP_DOC_CNT) LEFT OUTER JOIN STOCCVUR CUR ON (SCTM.GATE_CD = CUR.GATE_CD AND SCTM.NEXT_SIGN_USER_ID = CUR.USER_ID) LEFT OUTER JOIN STOCCVUR RCUR ON (SCTM.GATE_CD = RCUR.GATE_CD AND SCTM.REG_USER_ID = RCUR.USER_ID) WHERE SCTM.GATE_CD = #{ses.gateCd} AND SCTP.SIGN_USER_ID = #{ses.userId} AND SCTM.DEL_FLAG = '0' AND SCTP.DEL_FLAG = '0'
AND ((SCTP.SIGN_STATUS IN ('E','R') AND SCTP.SIGN_REQ_TYPE IN ('E', 'ES', 'EP', 'A')) OR (SCTM.SIGN_STATUS = 'E' AND SCTP.SIGN_REQ_TYPE = 'CC')) AND SCTM.SIGN_STATUS IN ('P','E','R') AND SCTP.SIGN_USER_ID = #{ses.userId}
AND SCTP.SIGN_STATUS = 'P' AND SCTM.SIGN_STATUS = 'P' AND SCTM.NEXT_SIGN_USER_ID = #{ses.userId}
AND SCTM.REG_DATE >= (#{RFA_FROM_DATE}) AND SCTM.REG_DATE <= (#{RFA_TO_DATE})
AND SCTM.SIGN_STATUS = #{SIGN_STATUS}
AND SCTM.DOC_TYPE = #{DOCUMENT_TYPE}
AND UPPER(SCTM.REG_USER_ID) LIKE '%' UPPER(#{USER_ID}) '%'
AND UPPER(getUserName(SCTM.GATE_CD, SCTM.REG_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{USER_NM}) '%'
AND UPPER(REPLACE(SCTM.SUBJECT, ' ', '')) LIKE '%' UPPER(REPLACE(#{DOCUMENT_NM}, ' ', '')) '%'
ORDER BY SCTM.REG_DATE DESC

SELECT RULM.MAIN_PATH_FLAG ,GETCOMCODE(RULM.GATE_CD, 'M044', RULM.MAIN_PATH_FLAG, 0, #{ses.langCd}) AS MAIN_PATH_FLAG_LOC ,RULM.SIGN_PATH_NM ,(SELECT COUNT(*) FROM STOCLULP LULP WHERE LULP.GATE_CD = RULM.GATE_CD AND LULP.PATH_NUM = RULM.PATH_NUM AND LULP.DEL_FLAG = '0') AS SIGN_PERSON_CNT ,(SELECT COUNT(PATH_SQ) FROM STOCLULP LULP JOIN STOCCVUR USERTB ON (LULP.GATE_CD = USERTB.GATE_CD AND LULP.SIGN_USER_ID = USERTB.USER_ID) LEFT OUTER JOIN STOCOGDP OGDP ON (USERTB.GATE_CD = OGDP.GATE_CD AND USERTB.COMPANY_CD = OGDP.BUYER_CD AND USERTB.DEPT_CD = OGDP.DEPT_CD AND OGDP.DEL_FLAG = '0') WHERE LULP.GATE_CD = RULM.GATE_CD AND LULP.PATH_NUM = RULM.PATH_NUM AND LULP.DEL_FLAG = '0' AND USERTB.DEL_FLAG = '0') AS PATH_SQ ,RULM.SIGN_RMK ,(RULM.REG_DATE, 'yyyyMMdd') AS REG_DATE ,(MOD_DATE, 'yyyyMMdd') AS MOD_DATE ,RULM.GATE_CD ,RULM.PATH_NUM ,'' as MAIN_PATH_NM FROM STOCRULM RULM WHERE RULM.GATE_CD = #{ses.gateCd} AND RULM.DEL_FLAG = '0' AND RULM.PATH_USER_ID = #{ses.userId}
AND UPPER(RULM.SIGN_PATH_NM) LIKE '%' UPPER(#{SIGN_PATH_NM}) '%'
AND RULM.MAIN_PATH_FLAG = #{MAIN_PATH_FLAG}
ORDER BY REG_DATE DESC

