mapper.insert:
INSERT INTO STOCRULM (
	 GATE_CD
	,PATH_NUM
	,REG_DATE
	,REG_USER_ID
	,MOD_DATE
	,MOD_USER_ID
	,DEL_FLAG
	,MAIN_PATH_FLAG
	,SIGN_PATH_NM
	,SIGN_RMK
	,BUYER_CD
	,PATH_USER_ID
) VALUES (
	 #{ses.gateCd}
	,#{PATH_NUM}
	,SYSDATE
	,#{ses.userId}
	,SYSDATE
	,#{ses.userId}
	,'0'
	,(CASE WHEN (#{MAIN_PATH_FLAG}, '0') = 'on' THEN '1' ELSE '0' END)
	,#{SIGN_PATH_NM}
	,#{SIGN_RMK}
	,#{ses.companyCd}
	,#{ses.userId}
)

mapper.update:
UPDATE STOCRULM SET
	 MOD_USER_ID = #{ses.userId}
	,MOD_DATE = SYSDATE
	,MAIN_PATH_FLAG = (CASE WHEN (#{MAIN_PATH_FLAG}, '0') = 'on' THEN '1' ELSE '0' END)
	,SIGN_PATH_NM = #{SIGN_PATH_NM}
	,SIGN_RMK = #{SIGN_RMK}
 WHERE GATE_CD = #{ses.gateCd}
   AND PATH_NUM = #{PATH_NUM}

mapper.delete:
		DELETE STOCLULP
		 WHERE GATE_CD = #{ses.gateCd}
           AND PATH_NUM = #{PATH_NUM}

mapper.insert:
INSERT INTO STOCLULP (
	 GATE_CD
	,PATH_NUM
	,PATH_SQ
	,REG_DATE
	,REG_USER_ID
	,MOD_DATE
	,MOD_USER_ID
	,DEL_FLAG
	,SIGN_PATH_SQ
	,SIGN_REQ_STATUS
	,SIGN_USER_ID
) VALUES (
	 #{ses.gateCd}
	,#{PATH_NUM}
	,(SELECT (MAX(PATH_SQ) + 1, 1) FROM STOCLULP WHERE GATE_CD = #{ses.gateCd} AND PATH_NUM = #{PATH_NUM})
	,SYSDATE
	,#{ses.userId}
	,SYSDATE
	,#{ses.userId}
	,'0'
	,(SELECT (MAX(SIGN_PATH_SQ) + 1, 1) FROM STOCLULP WHERE GATE_CD = #{ses.gateCd} AND PATH_NUM = #{PATH_NUM})
	,#{SIGN_REQ_STATUS}
	,#{SIGN_USER_ID}
)

mapper.update:
UPDATE STOCRULM SET
     MOD_USER_ID = #{ses.userId}
    ,MOD_DATE = SYSDATE
    ,MAIN_PATH_FLAG = '0'
 WHERE GATE_CD = #{ses.gateCd}
   AND PATH_USER_ID = #{ses.userId}
   AND PATH_NUM != #{PATH_NUM}

mapper.select:
SELECT B.SIGN_USER_ID, B.SIGN_USER_NM ,B.CUST_CD, B.CUST_NM ,B.DEPT_CD, B.DEPT_NM ,B.POSITION_NM FROM ( SELECT A.SIGN_USER_ID, A.SIGN_USER_NM ,A.CUST_CD, A.CUST_NM ,A.DEPT_CD ,A.DEPT_NM --,(SELECT MAX(DP.DEPT_NM) FROM STOCOGDP DP WHERE DP.GATE_CD = A.GATE_CD AND DP.BUYER_CD = A.COMPANY_CD AND DP.DEL_FLAG = '0') AS DEPT_NM ,A.POSITION_NM FROM ( SELECT /*+ INDEX(STOCCVUR IDX_CVUR_01) */ UR.USER_ID AS SIGN_USER_ID, UR.USER_NM AS SIGN_USER_NM, UR.DEPT_CD, OGDP.DEPT_NM, UR.DUTY_NM AS POSITION_NM, CUST.CUST_CD, CUST.CUST_NM, UR.GATE_CD, UR.COMPANY_CD FROM STOCCVUR UR LEFT JOIN STOCCUST CUST ON (UR.GATE_CD = CUST.GATE_CD AND UR.COMPANY_CD = CUST.CUST_CD AND CUST.DEL_FLAG = '0') LEFT JOIN STOCOGDP OGDP ON (UR.GATE_CD = OGDP.GATE_CD AND UR.COMPANY_CD = OGDP.BUYER_CD AND UR.DEPT_CD = OGDP.DEPT_CD) WHERE UR.GATE_CD = #{ses.gateCd} AND UR.USER_TYPE = 'B' AND UR.DEL_FLAG = '0' AND UR.PROGRESS_CD = 'E' AND UR.COMPANY_CD = #{CUST_CD}
AND UPPER(CUST.CUST_NM) LIKE '%' UPPER(#{COMPANY}) '%'
AND UPPER(OGDP.DEPT_NM) LIKE '%' UPPER(#{DEPT_CD}) '%'
) A WHERE 1 = 1
AND UPPER(A.SIGN_USER_NM) LIKE '%' UPPER(#{SIGN_USER_NM}) '%'
) B WHERE 1 = 1
ORDER BY B.CUST_NM, B.DEPT_NM, B.POSITION_NM, B.SIGN_USER_NM

SELECT
	APP_LINE, AGR_LINE
  FROM STOCDMLR DMLR
 WHERE DMLR.GATE_CD = #{ses.gateCd}
   AND DMLR.DEL_FLAG = '0'
   AND DMLR.USE_FLAG = '1'
   AND DMLR.CUST_CD = #{CUST_CD}
   AND DMLR.BIZ_CLS1 = #{BIZ_CLS1}
   AND DMLR.BIZ_CLS2 = #{BIZ_CLS2}
   AND DMLR.BIZ_CLS3 = #{BIZ_CLS3}
   AND DMLR.APP_DATE <= SYSDATE

	AND TO_NUMBER(#{BIZ_AMT}) BETWEEN DMLR.FROM_AMT AND DMLR.TO_AMT


	AND CONVERT(numeric, #{BIZ_AMT}) BETWEEN DMLR.FROM_AMT AND DMLR.TO_AMT

SELECT * FROM (
SELECT #{item.SIGN_TYPE} AS SIGN_REQ_TYPE, #{item.SIGN_PATH_SQ} AS SIGN_PATH_SQ, UR.USER_ID AS SIGN_USER_ID, UR.USER_NM AS SIGN_USER_NM, UR.DEPT_CD, DP.DEPT_NM, UR.POSITION_NM FROM STOCUSER UR LEFT JOIN STOCOGDP DP ON (UR.DEPT_CD = DP.DEPT_CD AND UR.COMPANY_CD = DP.BUYER_CD AND DP.DEL_FLAG = '0' AND UR.GATE_CD = DP.GATE_CD) WHERE UR.GATE_CD = #{ses.gateCd} AND UR.USER_TYPE = 'B' AND UR.DEL_FLAG = '0' AND UR.USER_ID = #{item.USER_ID}
)
ORDER BY TO_NUMBER(SIGN_PATH_SQ)
ORDER BY CONVERT(NUMERIC(22), SIGN_PATH_SQ)

SELECT CUST_CD "value", CUST_NM "text"
FROM STOCCUST
WHERE GATE_CD = #{ses.gateCd}
AND RELAT_YN  = #{RELAT_YN}
AND CORP_TYPE = #{CORP_TYPE}
AND DEL_FLAG  = '0'

SELECT CUST_CD "value", CUST_NM "text"
FROM STOCCUST
WHERE GATE_CD = #{ses.gateCd}
AND RELAT_YN  = #{RELAT_YN}
AND CORP_TYPE = #{CORP_TYPE}
AND CUST_CD = #{ses.companyCd}
AND DEL_FLAG  = '0'
